with open(p,'r',encoding='utf-8') as f:
    data = json.load(f)
US_STATES = set(["AL","AK","AZ","AR","CA","CO","CT","DE","FL","GA","HI","ID","IL","IN","IA","KS","KY","LA","ME","MD","MA","MI","MN","MS","MO","MT","NE","NV","NH","NJ","NM","NY","NC","ND","OH","OK","OR","PA","RI","SC","SD","TN","TX","UT","VT","VA","WA","WV","WI","WY"])

def offers_wifi_val(val):
    if val is None:
        return False
    s = str(val).lower()
    # remove leading u and quotes
    s = s.replace("u'","'").replace('"','').replace("'","")
    s = s.strip()
    if s=='' or s in ('none','null','nan'):
        return False
    if 'no' == s or s.startswith('no'):
        return False
    if any(k in s for k in ('free','paid','yes','limited','signal','true')):
        return True
    # otherwise consider false
    return False

state_to_brefs = {}
for rec in data:
    attrs = rec.get('attributes')
    wifi_val = None
    if isinstance(attrs, dict):
        wifi_val = attrs.get('WiFi')
    else:
        wifi_val = None
    if not offers_wifi_val(wifi_val):
        continue
    desc = rec.get('description','') or ''
    # find all uppercase two-letter groups
    matches = re.findall(r"\b([A-Z]{2})\b", desc)
    state = None
    for m in matches:
        if m in US_STATES:
            state = m
            break
    if not state:
        # try looking for like ', City, ST' with ST possibly lower
        m2 = re.search(r',\s*([A-Za-z]{2})\b', desc)
        if m2:
            cand = m2.group(1).upper()
            if cand in US_STATES:
                state = cand
    if not state:
        continue
    bid = rec.get('business_id')
    if not bid:
        continue
    bref = bid.replace('businessid_','businessref_')
    state_to_brefs.setdefault(state, []).append(bref)

if not state_to_brefs:
    out = {"top_state": None, "count": 0, "business_refs": []}
else:
    counts = {s: len(set(brefs)) for s,brefs in state_to_brefs.items()}
    max_count = max(counts.values())
    top_states = [s for s,c in counts.items() if c==max_count]
    top_state = sorted(top_states)[0]
    brefs = sorted(list(set(state_to_brefs[top_state])))
    out = {"top_state": top_state, "count": max_count, "business_refs": brefs}

print('__RESULT__:')
print(json.dumps(out))"}

