{"code":"import json, re
p = var_call_dTdMzELB4RK2SW9tG9NA5SiF
with open(p, 'r', encoding='utf-8') as f:
    data = json.load(f)
US_STATES = {"AL","AK","AZ","AR","CA","CO","CT","DE","FL","GA","HI","ID","IL","IN","IA","KS","KY","LA","ME","MD","MA","MI","MN","MS","MO","MT","NE","NV","NH","NJ","NM","NY","NC","ND","OH","OK","OR","PA","RI","SC","SD","TN","TX","UT","VT","VA","WA","WV","WI","WY"}

def offers_wifi(val):
    if val is None:
        return False
    s = str(val).lower()
    # remove leading u' markers and quotes and whitespace
    s = s.replace("u'", "'")
    s = s.strip()
    s = s.strip("\"')")
    s = s.strip("\"')(")
    s = s.replace(' ', '')
    if s in ('none','null','nan',''):
        return False
    if s.startswith('no') or s == 'no':
        return False
    # consider free/paid/yes/limited as offering
    if 'free' in s or 'paid' in s or 'yes' in s or 'limited' in s or 'signal' in s:
        return True
    # some entries might be 'True' or 'true'
    if s in ('true','t'):
        return True
    # default: if not explicitly no, consider offering
    return True

state_counts = {}
state_to_brefs = {}
for rec in data:
    attrs = rec.get('attributes')
    wifi_val = None
    if isinstance(attrs, dict):
        wifi_val = attrs.get('WiFi')
    else:
        wifi_val = None
    if not offers_wifi(wifi_val):
        continue
    desc = rec.get('description','') or ''
    # find patterns like ', ST' or 'in City, ST'
    m = re.search(r'in [^,]+,\s*([A-Z]{2})\b', desc)
    if not m:
        m = re.search(r',\s*([A-Z]{2})\b', desc)
    if not m:
        continue
    state = m.group(1)
    if state not in US_STATES:
        continue
    bid = rec.get('business_id')
    if not bid:
        continue
    bref = bid.replace('businessid_','businessref_')
    state_counts[state] = state_counts.get(state, 0) + 1
    state_to_brefs.setdefault(state, []).append(bref)

# find top state(s)
if not state_counts:
    out = {"top_state": None, "count": 0, "business_refs": []}
else:
    max_count = max(state_counts.values())
    top_states = [s for s,c in state_counts.items() if c==max_count]
    top_state = sorted(top_states)[0]
    # deduplicate business refs
    brefs = sorted(list(set(state_to_brefs.get(top_state,[]))))
    out = {"top_state": top_state, "count": max_count, "business_refs": brefs}

print('__RESULT__:')
print(json.dumps(out))"}

